// worker/src/index.js — Cloudflare Worker entry point
import { Router } from 'itty-router';

import { requireAuth }    from './auth.js';
import sessionRoutes      from './routes/session.js';
import historyRoutes      from './routes/history.js';
import statsRoutes        from './routes/stats.js';
import leaderboardRoutes  from './routes/leaderboard.js';
import cardsRoutes        from './routes/cards.js';
import accountRoutes      from './routes/account.js';

const router = Router();

// ── CORS preflight ─────────────────────────────────────────────────────────
router.options('*', (request, env) => {
  return new Response(null, {
    status: 204,
    headers: corsHeaders(env),
  });
});

// ── Health check (unauthenticated) ─────────────────────────────────────────
router.get('/health', (_req, env) =>
  json({ status: 'ok', project: env.FIREBASE_PROJECT_ID }, env)
);

// ── Authenticated routes ───────────────────────────────────────────────────
router.all('/api/session/*',     sessionRoutes.handle);
router.all('/api/history/*',     historyRoutes.handle);
router.all('/api/stats/*',       statsRoutes.handle);
router.all('/api/leaderboard/*', leaderboardRoutes.handle);
router.all('/api/cards/*',       cardsRoutes.handle);
router.all('/api/account/*',     accountRoutes.handle);

// ── 404 fallback ───────────────────────────────────────────────────────────
router.all('*', (_req, env) =>
  json({ error: 'Not Found' }, env, 404)
);

// ── Export ──────────────────────────────────────────────────────────────────
export default {
  async fetch(request, env, ctx) {
    try {
      const response = await router.handle(request, env, ctx);
      // Attach CORS headers to every response
      const headers = new Headers(response.headers);
      const cors    = corsHeaders(env);
      for (const [k, v] of Object.entries(cors)) headers.set(k, v);
      return new Response(response.body, {
        status:  response.status,
        headers,
      });
    } catch (err) {
      console.error('[worker] unhandled error:', err);
      return new Response(JSON.stringify({ error: 'Internal Server Error' }), {
        status:  500,
        headers: { 'Content-Type': 'application/json' },
      });
    }
  },
};

// ── Helpers ─────────────────────────────────────────────────────────────────
export function json(data, env, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...corsHeaders(env),
    },
  });
}

export function corsHeaders(env) {
  const origin = env?.ALLOWED_ORIGIN ?? '*';
  return {
    'Access-Control-Allow-Origin':  origin,
    'Access-Control-Allow-Methods': 'GET, POST, PUT, PATCH, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    'Access-Control-Max-Age':       '86400',
  };
}
